import{_ as t,o as a,c as i,ai as s}from"./chunks/framework.CKB5fCPB.js";const p=JSON.parse('{"title":"Threat model","description":"","frontmatter":{},"headers":[],"relativePath":"Lore/Threat model.md","filePath":"Lore/Threat model.md"}'),n={name:"Lore/Threat model.md"};function o(l,e,r,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to “Threat model”">​</a></h1><p>This document will talk about possible issues and precautionary measurements that have been made to try to best combat issues and to be transparent of possible weaknesses.</p><hr><h2 id="trust-assumptions" tabindex="-1">Trust assumptions <a class="header-anchor" href="#trust-assumptions" aria-label="Permalink to “Trust assumptions”">​</a></h2><ol><li>The server has full authority</li><li>Users trust instances they connect to.</li><li>Other (federated) instances are not trusted by default</li><li>Clients are not trusted by default</li></ol><hr><h2 id="potential-threats" tabindex="-1">Potential threats <a class="header-anchor" href="#potential-threats" aria-label="Permalink to “Potential threats”">​</a></h2><p>This is a list of potential issues that may surface and scenarios that could potentially occur. The list may not be complete but should give a rough understanding.</p><h3 id="compromised-instance" tabindex="-1">Compromised instance <a class="header-anchor" href="#compromised-instance" aria-label="Permalink to “Compromised instance”">​</a></h3><ol><li>Account takeovers</li><li>Malicious instance operator</li><li>Hacked server</li><li>Potential data leak</li><li>MITM server side public key exchange</li></ol><h3 id="dsync-federation" tabindex="-1">dSync Federation <a class="header-anchor" href="#dsync-federation" aria-label="Permalink to “dSync Federation”">​</a></h3><ol><li>Spam/Abuse events</li><li>Malicious events (fake bans)</li><li>Identity spoofing</li></ol><h3 id="user-attacks" tabindex="-1">User Attacks <a class="header-anchor" href="#user-attacks" aria-label="Permalink to “User Attacks”">​</a></h3><ol><li>Spam</li><li>Token theft</li><li>Exported Account theft</li><li>Brute force logins</li><li>XSS or other possible vulnerabilities</li><li>Ban evading</li><li>Private key theft</li></ol><hr><h2 id="mitigations" tabindex="-1">Mitigations <a class="header-anchor" href="#mitigations" aria-label="Permalink to “Mitigations”">​</a></h2><h3 id="compromised-instance-1" tabindex="-1">Compromised instance <a class="header-anchor" href="#compromised-instance-1" aria-label="Permalink to “Compromised instance”">​</a></h3><ol><li>None. Responsibility lies within the instance operator.</li></ol><h3 id="dsync-federation-1" tabindex="-1">dSync Federation <a class="header-anchor" href="#dsync-federation-1" aria-label="Permalink to “dSync Federation”">​</a></h3><ol><li>Implemented rate limits. Plans for abuse events and bundling them to avoid forcing a server to spam penalty events making a trustworthy node a potential spammer.</li><li>Penalty events and possibly blocking the emitter node. Reducing trust until it will be automatically blocked due to a threshold limit and being potentially blocked by all nodes if setup to do so.</li><li>All events are cryptographically signed. Every node can independently verify events. Manipulations will be detected too. Penalty events will be broadcasted until the trust score hits the threshold and will be potentially blocked in the entire network as well, if nodes are setup to do so individually.</li></ol><h3 id="user-attacks-1" tabindex="-1">User Attacks <a class="header-anchor" href="#user-attacks-1" aria-label="Permalink to “User Attacks”">​</a></h3><ol><li>Various rate limits and a new rate limit system thats dynamic and will be based on community activity. Based on per channel and user and as accurate as to the current hour. IP based checking for VPNs, proxies, datacenter ips (bots/spam services) and more.</li><li>None yet. Its possible to rotate ALL user tokens, but not specific ones yet. There are plans to add IP based checks like country changes, carrier change or similar to block this from being possible, but not implemented yet. Contact an instance admin.</li><li>None. Same as 2.</li><li>Login try limit and automatic temporary ban. Possible enhancement: Let admins and the affected user know about failed attempts.</li><li>Many filters in the server as well as client side to prevent unsanitized input from the server to cauz problems in the client. In case something does happen, patch it asap, create a security release and be transparent about and let people know. Staying up to date from a code perspective. Enhancement: Add more automatic test cases that explicitly target these.</li><li>Advanced IP based filtering for VPNs, Tor connections, datacenter connections and more. While not impossible to bypass, it will make it harder and has been proven to work so far.</li><li>A &quot;bridge&quot; has been made using the preloader in electron to block direct access to any of the encryption related functions which in theory should be impossible to steal the private key <em>from the web client</em> as electron should isolate it. This has been roughly tested and was not possible so far, tho maybe someone with more expertise could test this theory more extensively. If stolen an attacker could read encrypted DMs or authenticate with it. <strong>Further testing is needed!</strong></li></ol><hr><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to “Non-Goals”">​</a></h2><p>There are also some things DCTS wont do:</p><ul><li>protect against malicious instance operators</li><li>guarantee global moderation fairness</li><li>prevent illegal content and activities</li><li>protect against OS level compromises</li><li>protect against data leaks</li><li>protect against &quot;stolen accounts&quot;</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>There are potential plans for the future to implement a warning screen for known malicious instances, but this is still a concept and not implemented as of right now.</p></div>',27)])])}const u=t(n,[["render",o]]);export{p as __pageData,u as default};
